        subscriptions[msg.sender] = expiration + 30 days;
        emit SubscriptionPurchased(msg.sender, subscriptions[msg.sender]);
    }

    function isActive(address user) external view returns (bool) {
        return subscriptions[user] > block.timestamp;
    }

    function getExpiration(address user) external view returns (uint256) {
        return subscriptions[user];
    }

    function getPrice() external view returns (uint256) {
        return subscriptionPrice;
    }

    function updateSubscriptionPrice(uint256 _newPrice) external onlyOwner {
        subscriptionPrice = _newPrice;
        emit PriceUpdated(subscriptionPrice);
    }

    function withdrawFunds() external onlyOwner {
        uint256 amount = address(this).balance;
        payable(owner).transfer(amount);
        emit FundsWithdrawn(owner, amount);
    }
}
