Below is the revised contract incorporating the above recommendations:

```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract SubscriptionManager is Ownable, ReentrancyGuard {
    uint256 public subscriptionPrice;
    mapping(address => uint256) private subscriptions;

    event SubscriptionPurchased(address indexed user, uint256 expiration);
    event PriceUpdated(uint256 newPrice);
    event FundsWithdrawn(address indexed owner, uint256 amount);

    constructor() {
        subscriptionPrice = 0.01 ether; // Default price set to 0.01 ETH
    }

    function purchaseSubscription() public payable nonReentrant {
        require(msg.value >= subscriptionPrice, "Insufficient funds");

        uint256 expiration = block.timestamp + 30 days;
        if (subscriptions[msg.sender] > 0) {
            expiration = subscriptions[msg.sender] + 30 days;
        }

        subscriptions[msg.sender] = expiration;
        emit SubscriptionPurchased(msg.sender, expiration);
    }

    function updateSubscriptionPrice(uint256 newPrice) public onlyOwner {
        require(newPrice > 0, "New price must be greater than zero");
        subscriptionPrice = newPrice;
        emit PriceUpdated(newPrice);
    }

    function withdrawFunds() public onlyOwner nonReentrant {
        uint256 balance = address(this).balance;
        (bool success, ) = owner.call{value: balance}("");
        require(success, "Transfer failed");
        emit FundsWithdrawn(owner, balance);
    }

    function getExpiration(address user) public view returns (uint256) {
        return subscriptions[user];
    }

    function getPrice() public view returns (uint256) {
        return subscriptionPrice;
    }

    function isActive(address user) public view returns (bool) {
        return subscriptions[user] > block.timestamp;
    }
}
```

### Key Changes:
1. **SPDX License Identifier**: Added at the top of the file.
2. **ReentrancyGuard**: Used `nonReentrant` modifier to prevent reentrancy attacks.
3. **Ownable**: Inherited from `Ownable` for secure ownership management.
4. **Error Handling**: Ensured that `withdrawFunds` reverts if the transfer fails.
5. **Event Emission**: All state-changing operations now emit appropriate events.
6. **Gas Optimization**: Minimized storage writes and ensured efficient operations.

By addressing these issues, the contract should now be more secure, functional, and gas-efficient.

